import{Logger}from '../../shared/logger.js';const STORAGE_KEY='sadec-quick-notes';export function loadNotes(){try{const stored=localStorage.getItem(STORAGE_KEY);const notes=stored ? JSON.parse(stored): [];Logger.debug('[QuickNotes Storage] Loaded',notes.length,'notes');return notes;}catch(error){Logger.error('[QuickNotes Storage] Load error:',error);return [];}}export function saveNotes(notes){try{localStorage.setItem(STORAGE_KEY,JSON.stringify(notes));Logger.debug('[QuickNotes Storage] Saved',notes.length,'notes');}catch(error){Logger.error('[QuickNotes Storage] Save error:',error);}}export function createNote(content,color){return{id: Date.now().toString(),content,color,createdAt: new Date().toISOString(),updatedAt: new Date().toISOString()};}export function updateNote(notes,noteId,updates){return notes.map(note=>{if(note.id===noteId){return{...note,...updates,updatedAt: new Date().toISOString()};}return note;});}export function deleteNote(notes,noteId){return notes.filter(n=>n.id!==noteId);}export function reorderNotes(notes,draggedId,targetId,insertBefore){const draggedIndex=notes.findIndex(n=>n.id===draggedId);const targetIndex=notes.findIndex(n=>n.id===targetId);if(draggedIndex===-1||targetIndex===-1)return notes;const [draggedNote]=notes.splice(draggedIndex,1);const newTargetIndex=notes.findIndex(n=>n.id===targetId);const insertIndex=insertBefore ? newTargetIndex : newTargetIndex+1;notes.splice(insertIndex,0,draggedNote);return notes;}